def average_cash_paid_for_interest():
    # Filter rows for the years 2014-2016
    debt_rows = row_values("total debt", col_filter=["2016", "2015"])

    # Calculate the average cash paid for interest
    total_interest = 0
    count = 0
    for debt in debt_rows:
        if debt is not None:
            total_interest += debt
            count += 1

    if count > 0:
        result = total_interest / count
